277→fn render_help_bar(frame: &mut Frame, area: Rect, state: &SearchOverlayState) {
278→    let key_style = Style::default().fg(Color::Yellow);
279→    let desc_style = Style::default().fg(Color::DarkGray);
280→
281→    let result_count = format!(
282→        "{} result{}",
283→        state.results.len(),
284→        if state.results.len() == 1 { "" } else { "s" }
285→    );
286→
287→    let left_spans = if state.loading {
288→        vec![
289→            Span::styled("Esc", key_style),
290→            Span::styled(" Cancel", desc_style),
291→        ]
292→    } else if state.results.is_empty() {
293→        vec![
294→            Span::styled("Enter", key_style),
295→            Span::styled(" Search  ", desc_style),
296→            Span::styled("Esc", key_style),
297→            Span::styled(" Close", desc_style),
298→        ]
299→    } else {
300→        vec![
301→            Span::styled("Enter", key_style),
302→            Span::styled(" Open  ", desc_style),
303→            Span::styled("\u{2191}/\u{2193}", key_style),
304→            Span::styled(" Navigate  ", desc_style),
305→            Span::styled("Esc", key_style),
306→            Span::styled(" Close", desc_style),
307→        ]
308→    };
309→
310→    let right_span = Span::styled(result_count, desc_style);
311→
312→    let left = Paragraph::new(Line::from(left_spans));
313→    let right = Paragraph::new(Line::from(right_span)).alignment(Alignment::Right);
314→
315→    frame.render_widget(left, area);
316→    frame.render_widget(right, area);
317→}
