319→// ---------------------------------------------------------------------------
320→// Key handling
321→// ---------------------------------------------------------------------------
322→
323→/// Handle key events for the search overlay.
324→pub fn handle_key(key: KeyEvent, state: &mut SearchOverlayState) -> SearchOverlayAction {
325→    // Ctrl-modified chars first.
326→    if key.modifiers.contains(KeyModifiers::CONTROL) {
327→        return match key.code {
328→            KeyCode::Char('n') => {
329→                state.select_next();
330→                SearchOverlayAction::None
331→            }
332→            KeyCode::Char('p') => {
333→                state.select_prev();
334→                SearchOverlayAction::None
335→            }
336→            KeyCode::Char('u') => {
337→                state.input.clear();
338→                state.selected = 0;
339→                state.list_state.select(None);
340→                SearchOverlayAction::None
341→            }
342→            _ => SearchOverlayAction::None,
343→        };
344→    }
345→
346→    match key.code {
347→        KeyCode::Esc => SearchOverlayAction::Close,
348→
349→        KeyCode::Enter => {
350→            // If results exist, open the selected one.
351→            if !state.results.is_empty()
352→                && let Some(result) = state.results.get(state.selected)
353→            {
354→                return SearchOverlayAction::OpenCheckpoint(result.checkpoint_idx);
355→            }
356→            // Otherwise, trigger search if there's a query.
357→            if state.input.is_empty() {
358→                SearchOverlayAction::None
359→            } else {
360→                SearchOverlayAction::TriggerSearch
361→            }
362→        }
363→
364→        KeyCode::Down => {
365→            state.select_next();
366→            SearchOverlayAction::None
367→        }
368→
369→        KeyCode::Up => {
370→            state.select_prev();
371→            SearchOverlayAction::None
372→        }
373→
374→        KeyCode::Backspace => {
375→            state.input.pop();
376→            // Clear results when query changes.
377→            if state.input.is_empty() {
378→                state.results.clear();
379→                state.last_searched_query = None;
380→                state.list_state.select(None);
381→                state.error = None;
382→            }
383→            SearchOverlayAction::None
384→        }
385→
386→        // All other printable chars go to the input buffer.
387→        KeyCode::Char(c) => {
388→            state.input.push(c);
389→            SearchOverlayAction::None
390→        }
391→
392→        _ => SearchOverlayAction::None,
393→    }
394→}
395→
396→// ---------------------------------------------------------------------------
397→// Internal helpers
398→// ---------------------------------------------------------------------------
399→
400→fn centered_rect(width: u16, height: u16, area: Rect) -> Rect {
401→    let x = area.x + (area.width.saturating_sub(width)) / 2;
402→    let y = area.y + (area.height.saturating_sub(height)) / 2;
403→    Rect::new(x, y, width.min(area.width), height.min(area.height))
404→}
405→
406→fn truncate(s: &str, max_width: usize) -> String {
407→    super::text_utils::truncate(s, max_width)
408→}
