222→    async fn handle_dashboard_key(&mut self, key: KeyEvent) {
223→        match key.code {
224→            KeyCode::Char('q') => self.running = false,
225→            KeyCode::Char('j') | KeyCode::Down => self.select_next(),
226→            KeyCode::Char('k') | KeyCode::Up => self.select_prev(),
