291→    fn handle_diff_key(&mut self, key: KeyEvent, hash: &str) {
292→        let diffs = self
293→            .cache
294→            .cached_diffs(hash)
295→            .map(<[mementor_lib::git::diff::FileDiff]>::to_vec)
296→            .unwrap_or_default();
297→        let action = diff_view::handle_key(key, &mut self.diff_state, &diffs);
298→        match action {
299→            diff_view::DiffViewAction::Back => {
300→                // Go back to wherever we came from. For simplicity, go to
301→                // checkpoint list. A proper back-stack could be added later.
302→                self.view = View::CheckpointList;
303→            }
304→            diff_view::DiffViewAction::None => {}
305→        }
306→    }
307→
308→    async fn handle_git_log_key(&mut self, key: KeyEvent) {
309→        let commits = self.cache.commits().to_vec();
310→        let action = git_log::handle_key(key, &mut self.git_log_state, &commits);
311→        match action {
312→            git_log::GitLogAction::Back => {
313→                self.view = View::CheckpointList;
314→            }
315→            git_log::GitLogAction::OpenCheckpoint(cp_id) => {
316→                // Find checkpoint index by checkpoint_id.
317→                if let Some(idx) = self
318→                    .cache
319→                    .checkpoints()
320→                    .iter()
321→                    .position(|c| c.checkpoint_id == cp_id)
322→                {
323→                    self.open_detail(idx).await;
324→                }
325→            }
326→            git_log::GitLogAction::OpenDiff(hash) => {
327→                self.open_diff(&hash).await;
328→            }
329→            git_log::GitLogAction::None => {}
330→        }
331→    }
332→
333→    async fn open_detail(&mut self, checkpoint_idx: usize) {
334→        let session_count = self
335→            .cache
336→            .checkpoints()
337→            .get(checkpoint_idx)
338→            .map_or(0, |cp| cp.sessions.len());
339→        self.detail_state.reset(session_count);
340→        self.view = View::CheckpointDetail(checkpoint_idx);
341→
342→        // Eagerly load transcript for the first session.
343→        if let Some(cp) = self.cache.checkpoints().get(checkpoint_idx).cloned() {
344→            self.load_transcript_for_session(&cp, 0).await;
345→        }
346→    }
347→
348→    async fn open_diff(&mut self, commit_hash: &str) {
349→        // Pre-load diffs.
350→        let _ = self.cache.diffs(commit_hash).await;
351→        self.diff_state.reset();
352→        self.view = View::DiffView(commit_hash.to_owned());
353→    }
354→
355→    async fn load_transcript_for_session(
356→        &mut self,
357→        cp: &mementor_lib::model::CheckpointMeta,
358→        session_idx: usize,
359→    ) {
360→        if let Some(session) = cp.sessions.get(session_idx)
361→            && !session.blob_path.is_empty()
362→            && let Ok(entries) = self.cache.transcript(&session.blob_path).await
363→        {
364→            self.loaded_transcript = Some(entries.to_vec());
365→            return;
366→        }
367→        self.loaded_transcript = None;
368→    }
369→
370→    fn open_search(&mut self) {
371→        self.search_state.reset();
372→        self.search_open = true;
373→    }
374→
375→    async fn handle_search_action(&mut self, action: search::SearchOverlayAction) {
376→        match action {
377→            search::SearchOverlayAction::Close => {
378→                self.cancel_ai_search();
379→                self.search_open = false;
380→            }
381→            search::SearchOverlayAction::OpenCheckpoint(idx) => {
382→                self.search_open = false;
383→                self.open_detail(idx).await;
384→            }
385→            search::SearchOverlayAction::TriggerSearch => {
386→                self.start_ai_search();
387→            }
388→            search::SearchOverlayAction::None => {}
389→        }
390→    }
391→
392→    fn start_ai_search(&mut self) {
393→        // Cancel any in-flight search.
394→        self.cancel_ai_search();
395→
396→        let query = self.search_state.input.clone();
397→        self.search_state.loading = true;
398→        self.search_state.error = None;
399→        self.search_state.elapsed_ticks = 0;
400→        self.search_state.results.clear();
401→        self.search_state.list_state.select(None);
402→        self.search_state.last_searched_query = Some(query.clone());
403→
404→        self.ai_search_handle = Some(mementor_lib::ai_search::spawn_ai_search(query));
405→    }
406→
407→    fn cancel_ai_search(&mut self) {
408→        if let Some(handle) = self.ai_search_handle.take() {
409→            handle.abort();
410→        }
411→        self.search_state.loading = false;
412→    }
413→
414→    fn poll_ai_search(&mut self) {
415→        // Increment spinner tick while loading.
416→        if self.search_state.loading {
417→            self.search_state.elapsed_ticks += 1;
418→        }
419→
420→        let Some(handle) = &self.ai_search_handle else {
421→            return;
422→        };
423→        if !handle.is_finished() {
424→            return;
425→        }
426→
427→        // Take the handle — we know it's finished so try_join is instant.
428→        let handle = self.ai_search_handle.take().unwrap();
429→        self.search_state.loading = false;
430→
431→        // Use now_or_never since we confirmed is_finished().
432→        let Some(join_result) = futures::FutureExt::now_or_never(handle) else {
433→            return;
434→        };
435→        match join_result {
436→            Ok(Ok(results)) => self.apply_ai_results(results),
437→            Ok(Err(e)) => {
438→                self.search_state.error = Some(format!("{e}"));
439→            }
440→            Err(e) if e.is_cancelled() => {
441→                // Search was cancelled — do nothing.
442→            }
443→            Err(e) => {
444→                self.search_state.error = Some(format!("search task panicked: {e}"));
445→            }
446→        }
447→    }
448→
449→    fn apply_ai_results(&mut self, results: Vec<AiSearchResult>) {
450→        use crate::views::text_utils::format_relative_time;
451→
452→        let checkpoints = self.cache.checkpoints();
453→        let commits = self.cache.commits();
454→
455→        self.search_state.results = results
456→            .into_iter()
457→            .filter_map(|r| {
458→                // Resolve checkpoint_id to index.
459→                let idx = checkpoints
460→                    .iter()
461→                    .position(|cp| cp.checkpoint_id.starts_with(&r.checkpoint_id))?;
462→                let cp = &checkpoints[idx];
463→
464→                // Find commit subject and time.
465→                let commit = commits
466→                    .iter()
467→                    .find(|c| cp.commit_hashes.contains(&c.hash));
468→                let title = commit.map_or_else(
469→                    || "untitled".to_owned(),
470→                    |c| c.subject.clone(),
471→                );
472→                let time_ago = commit
473→                    .map(|c| format_relative_time(&c.date))
474→                    .unwrap_or_default();
475→
476→                Some(search::SearchMatchDisplay {
477→                    checkpoint_idx: idx,
478→                    checkpoint_id: r.checkpoint_id,
479→                    title,
480→                    time_ago,
481→                    relevance: r.relevance,
482→                    snippet: r.snippet,
483→                })
484→            })
485→            .collect();
486→
487→        self.search_state.selected = 0;
488→        if self.search_state.results.is_empty() {
489→            self.search_state.list_state.select(None);
490→        } else {
491→            self.search_state.list_state.select(Some(0));
492→        }
493→    }
494→
495→    fn select_next(&mut self) {
496→        let len = self.cache.checkpoints().len();
497→        if len == 0 {
498→            return;
499→        }
500→        let i = self
501→            .list_state
502→            .selected()
503→            .map_or(0, |i| if i + 1 < len { i + 1 } else { i });
504→        self.list_state.select(Some(i));
505→    }
506→
507→    fn select_prev(&mut self) {
508→        let len = self.cache.checkpoints().len();
509→        if len == 0 {
510→            return;
511→        }
512→        let i = self
513→            .list_state
514→            .selected()
515→            .map_or(0, |i| i.saturating_sub(1));
516→        self.list_state.select(Some(i));
517→    }
518→
519→    pub(crate) fn clamp_selection(&mut self) {
520→        let len = self.cache.checkpoints().len();
521→        if len == 0 {
522→            self.list_state.select(None);
523→        } else if let Some(i) = self.list_state.selected()
524→            && i >= len
525→        {
526→            self.list_state.select(Some(len - 1));
527→        }
528→    }
529→
530→    async fn open_branch_popup(&mut self) {
531→        self.branches = list_branches().await.unwrap_or_default();
532→        let selected_index = self
533→            .branches
534→            .iter()
535→            .position(|b| b == &self.selected_branch)
536→            .unwrap_or(0);
537→        self.branch_list_state.select(Some(selected_index));
538→        self.branch_popup_open = true;
539→    }
540→}
