  1→use anyhow::{Context, Result, bail};
  2→use serde::Deserialize;
  3→use tokio::task::JoinHandle;
  4→
  5→const PROMPT_PREFIX: &str = r#"You are a knowledge miner. Given a query, search this git repository's
  6→history to find the most relevant information — code changes, design
  7→documents, architectural decisions, discussions, or any recorded context.
  8→
  9→You have full read-only shell access. Use any commands you need — git, grep,
 10→find, cat, etc. The `entire` CLI is also available for inspecting coding
 11→session checkpoints (`entire explain --help`).
 12→
 13→Checkpoint data lives on the `entire/checkpoints/v1` git branch. Each
 14→checkpoint has metadata.json with a checkpoint_id and branch name.
 15→
 16→What matters most is getting high-quality results fast. You may spawn
 17→sub-agents via the Task tool for parallel search. Return results within 30
 18→seconds.
 19→
 20→## Output format
 21→
 22→Your output MUST be parseable JSON only — no markdown, no conversation, no
 23→explanation. Output NOTHING except the JSON array.
 24→
 25→Write the `answer` field in the same language as the query.
 26→
 27→```json
 28→[
 29→  {
 30→    "source": {
 31→      "commit_sha": "...",
 32→      "pr": "..."
 33→    },
 34→    "answer": "..."
 35→  }
 36→]
 37→```
 38→
 39→- `source`: mandatory, at least one field (commit_sha, pr)
 40→- `answer`: mandatory, what you found and why it is relevant
 41→
 42→## Query
 43→
 44→"#;
 45→
 46→/// Source reference for an AI search result (commit, PR, or both).
 47→#[derive(Debug, Clone, Deserialize)]
 48→pub struct AiSearchSource {
 49→    pub commit_sha: Option<String>,
 50→    pub pr: Option<String>,
 51→}
 52→
 53→/// A single AI search result returned by Claude.
 54→#[derive(Debug, Clone, Deserialize)]
 55→pub struct AiSearchResult {
 56→    pub source: AiSearchSource,
 57→    pub answer: String,
 58→}
 59→
 60→/// Outer JSON envelope from `claude -p --output-format json`.
 61→#[derive(Debug, Deserialize)]
 62→struct ClaudeEnvelope {
 63→    #[serde(rename = "type")]
 64→    _type: String,
 65→    result: Option<String>,
 66→    is_error: Option<bool>,
 67→}
 68→
 69→/// Spawn an AI search as a background task. Claude explores the repo itself
 70→/// using tools (git, grep, entire CLI, etc.) and returns ranked results.
 71→pub fn spawn_ai_search(query: String) -> JoinHandle<Result<Vec<AiSearchResult>>> {
 72→    tokio::spawn(async move { run_ai_search(&query).await })
 73→}
 74→
 75→/// Run an agentic AI search by invoking `claude -p` with tool access so
 76→/// Claude can explore the repository history directly.
 77→async fn run_ai_search(query: &str) -> Result<Vec<AiSearchResult>> {
 78→    use tokio::process::Command;
 79→
 80→    let prompt = format!("{PROMPT_PREFIX}{query}");
 81→
 82→    let output = Command::new("claude")
 83→        .arg("-p")
 84→        .args(["--model", "haiku"])
 85→        .args(["--max-turns", "25"])
 86→        .args([
 87→            "--allowed-tools",
 88→            "Bash(entire:*) Bash(git:*) Bash(grep:*) Bash(rg:*) Bash(head:*) \
 89→             Bash(tail:*) Bash(wc:*) Bash(cat:*) Bash(jq:*) Bash(find:*) \
 90→             Bash(ls:*) Read Grep Glob LS Task",
 91→        ])
 92→        .args(["--disallowed-tools", "Edit Write NotebookEdit"])
 93→        .args(["--permission-mode", "bypassPermissions"])
 94→        .arg("--no-session-persistence")
 95→        .args(["--output-format", "json"])
 96→        .arg(&prompt)
 97→        .env_remove("CLAUDECODE")
 98→        .env_remove("CLAUDE_CODE_ENTRYPOINT")
 99→        .env_remove("CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS")
100→        .output()
101→        .await
102→        .context("failed to spawn claude CLI — is it installed?")?;
103→
104→    if !output.status.success() {
105→        let stderr = String::from_utf8_lossy(&output.stderr);
106→        bail!("claude exited with {}: {}", output.status, stderr.trim());
107→    }
108→
109→    let stdout =
110→        String::from_utf8(output.stdout).context("claude output is not valid UTF-8")?;
111→
112→    if stdout.trim().is_empty() {
113→        bail!("claude returned empty output");
114→    }
115→
116→    // Parse outer envelope.
117→    let envelope: ClaudeEnvelope =
118→        serde_json::from_str(&stdout).context("failed to parse claude JSON envelope")?;
119→
120→    if envelope.is_error == Some(true) {
121→        bail!(
122→            "claude returned an error: {}",
123→            envelope.result.as_deref().unwrap_or("unknown")
124→        );
125→    }
126→
127→    let Some(result_text) = envelope.result else {
128→        bail!("claude envelope missing 'result' field");
129→    };
130→
131→    // Strip markdown code fences if present.
132→    let json_text = strip_code_fences(&result_text);
133→
134→    // Parse inner JSON. If Haiku returned prose instead of valid JSON,
135→    // return empty results rather than propagating an error — the UI will
136→    // show "No results found".
137→    let results: Vec<AiSearchResult> =
138→        serde_json::from_str(json_text).unwrap_or_default();
139→
140→    Ok(results)
141→}
142→
143→/// Strip optional markdown code fences (```json ... ```) from Claude's output.
144→fn strip_code_fences(s: &str) -> &str {
145→    let trimmed = s.trim();
146→    if let Some(rest) = trimmed.strip_prefix("```") {
147→        // Skip the language tag on the first line.
148→        let rest = rest
149→            .find('\n')
150→            .map_or(rest, |idx| &rest[idx + 1..]);
151→        rest.strip_suffix("```").unwrap_or(rest).trim()
152→    } else {
153→        trimmed
154→    }
155→}
156→
157→#[cfg(test)]
158→mod tests {
159→    use super::*;
160→
161→    #[test]
